document.addEventListener("DOMContentLoaded", () => {
  const leftColumn = document.querySelector("#left-column");
  const rightColumn = document.querySelector("#right-column");

  // Populate content dynamically for each column
  productData.slice(0, 2).forEach((item) => {
    leftColumn.innerHTML += createContentItem(item);
  });

  productData.slice(2).forEach((item) => {
    rightColumn.innerHTML += createContentItem(item);
  });
});

const createContentItem = ({ title, description, icon }) => `
                <div class="row my-4">
                    <div class="col-3">
                        ${icon}
                    </div>
                    <div class="col ps-4">
                        <p class="fs-4">${title}</p>
                        <p class="text-secondary fs-6 fw-300">${description}</p>
                    </div>
                </div>`;
